class Solution:
    def longestConsecutive(self, nums):
        s = set(nums)
        best = 0
        for x in s:
            if x - 1 in s:
                continue
            length = 1
            y = x + 1
            while y in s:
                length += 1
                y += 1
            if length > best:
                best = length
        return best

