var longestConsecutive = function(nums) {
    const s = new Set(nums);
    let best = 0;
    for (const x of s) {
        if (s.has(x - 1)) continue;
        let length = 1, y = x + 1;
        while (s.has(y)) { length++; y++; }
        if (length > best) best = length;
    }
    return best;
};
